const raw = $json.text;

let jsonText = null;
const fenceMatch = raw.match(/```json\s*([\s\S]*?)```/i) || raw.match(/```\s*([\s\S]*?)```/);
if (fenceMatch) {
  jsonText = fenceMatch[1].trim();
} else {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    jsonText = raw.slice(start, end + 1);
  }
}

if (!jsonText) {
  throw new Error('No JSON object found in LLM response: ' + raw);
}

let narration;
try {
  narration = JSON.parse(jsonText);
} catch (err) {
  throw new Error('Failed to parse LLM JSON: ' + err.message + '\nRaw text: ' + jsonText);
}

const requiredFields = ['summary', 'reasoning'];
for (const field of requiredFields) {
  if (!(field in narration)) {
    throw new Error(`LLM narration missing required field: ${field}`);
  }
}

const classifyOutput = $node["Classify"].json;

return [{
  json: {
    customer_id: classifyOutput.customer_id,
    state: classifyOutput.state,
    nudge_eligible_steps: classifyOutput.nudge_eligible_steps,
    verdict: {
      risk_level: classifyOutput.classification.risk_level,
      recommended_action: classifyOutput.classification.recommended_action,
      risks: classifyOutput.classification.risks,
      summary: narration.summary,
      reasoning: narration.reasoning,
    },
  },
}];

